// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.packed;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNotEquals;

import org.junit.jupiter.api.Test;

class PackedLongSubsetTableTest {

	@Test
	void structurallyVerifiesCollisionsAndOnlyImprovesDerivedState() {
		PackedLongSubsetTable table = new PackedLongSubsetTable(2);
		long collision = 41L;

		int left = table.offerHashed(collision, 0b0011L, 100.0d, 120.0d, 1, 1, 0b1100L);
		int right = table.offerHashed(collision, 0b0101L, 80.0d, 90.0d, 2, 2, 0b1010L);
		int repeated = table.offerHashed(collision, 0b0011L, 50.0d, 60.0d, 3, 3, 0b1110L);

		assertNotEquals(left, right);
		assertEquals(left, repeated);
		assertEquals(0b0011L, table.mask(left));
		assertEquals(50.0d, table.rows(left));
		assertEquals(60.0d, table.cost(left));
		assertEquals(3, table.parentStateId(left));
		assertEquals(3, table.appendedFactorOrdinal(left));
		assertEquals(0b1110L, table.neighborMask(left));
	}
}
